import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Check, ChevronsUpDown, MapPin, Search, X } from "lucide-react";
import { useIsMobile } from "@/hooks/use-mobile";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerFooter,
} from "@/components/ui/drawer";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";

interface Restaurant {
  id: string;
  name?: string;
  name_zh?: string;
  name_en?: string;
  name_pt?: string;
  address?: string;
  type?: string | string[];
}

interface MultiRestaurantSelectDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  value: string[];
  onSelect: (restaurantIds: string[]) => void;
  restaurants: Restaurant[];
  required?: boolean;
  maxDisplay?: number;
}

const MultiRestaurantSelectDrawer = ({
  open,
  onOpenChange,
  value,
  onSelect,
  restaurants,
  required = false,
  maxDisplay = 2,
}: MultiRestaurantSelectDrawerProps) => {
  const { t } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const isMobile = useIsMobile();
  const [search, setSearch] = useState("");
  const [pendingValue, setPendingValue] = useState<string[]>(value);
  const [drawerHeight, setDrawerHeight] = useState<string>('85vh');

  // Monitor visualViewport to dynamically adjust drawer height
  useEffect(() => {
    if (!open || !isMobile) return;
    
    const viewport = window.visualViewport;
    if (!viewport) {
      setDrawerHeight('85vh');
      return;
    }
    
    const updateHeight = () => {
      const availableHeight = viewport.height;
      const targetHeight = Math.min(availableHeight * 0.85, availableHeight - 50);
      setDrawerHeight(`${targetHeight}px`);
    };
    
    updateHeight();
    viewport.addEventListener('resize', updateHeight);
    
    return () => {
      viewport.removeEventListener('resize', updateHeight);
    };
  }, [open, isMobile]);

  // Reset pending value when drawer opens
  const handleOpenChange = (newOpen: boolean) => {
    if (newOpen) {
      setPendingValue(value);
      setSearch("");
    }
    onOpenChange(newOpen);
  };

  // Filter restaurants based on search
  const filteredRestaurants = restaurants?.filter((r) => {
    if (!search) return true;
    const name = getLocalizedField(r, "name")?.toLowerCase() || "";
    const address = r.address?.toLowerCase() || "";
    const searchLower = search.toLowerCase();
    return name.includes(searchLower) || address.includes(searchLower);
  }) || [];

  // Toggle restaurant selection
  const toggleRestaurant = (restaurantId: string) => {
    setPendingValue((prev) => {
      if (prev.includes(restaurantId)) {
        return prev.filter((id) => id !== restaurantId);
      }
      return [...prev, restaurantId];
    });
  };

  // Handle confirm (mobile only)
  const handleConfirm = () => {
    onSelect(pendingValue);
    onOpenChange(false);
    setSearch("");
  };

  // Handle toggle (desktop - immediate)
  const handleDesktopToggle = (restaurantId: string) => {
    const newValue = value.includes(restaurantId)
      ? value.filter((id) => id !== restaurantId)
      : [...value, restaurantId];
    onSelect(newValue);
  };

  // Get selected restaurant names
  const getSelectedNames = () => {
    return value
      .map((id) => {
        const restaurant = restaurants?.find((r) => r.id === id);
        return restaurant ? getLocalizedField(restaurant, "name") : null;
      })
      .filter(Boolean) as string[];
  };

  const selectedNames = getSelectedNames();

  // Trigger button content
  const TriggerContent = () => {
    if (selectedNames.length === 0) {
      return (
        <span className="text-muted-foreground">
          {t("community.linkRestaurants", "关联餐厅")}
          {required && <span className="text-destructive ml-1">*</span>}
        </span>
      );
    }

    const displayNames = selectedNames.slice(0, maxDisplay);
    const remaining = selectedNames.length - maxDisplay;

    return (
      <span className="text-primary flex items-center gap-1 flex-wrap">
        {displayNames.map((name, i) => (
          <span key={i}>
            {name}{i < displayNames.length - 1 ? "、" : ""}
          </span>
        ))}
        {remaining > 0 && (
          <Badge variant="secondary" className="text-xs px-1.5 py-0">
            +{remaining}
          </Badge>
        )}
      </span>
    );
  };

  // Trigger button
  const triggerButton = (
    <button
      type="button"
      className="flex items-center gap-1 text-sm hover:text-primary transition-colors text-left"
      onClick={() => handleOpenChange(true)}
    >
      <TriggerContent />
      <ChevronsUpDown className="h-4 w-4 opacity-50 shrink-0" />
    </button>
  );

  // Restaurant item component
  const RestaurantItem = ({
    restaurant,
    isSelected,
    onToggle,
  }: {
    restaurant: Restaurant;
    isSelected: boolean;
    onToggle: () => void;
  }) => (
    <div
      className={cn(
        "flex items-start gap-3 py-3 px-3 rounded-lg cursor-pointer transition-colors",
        isSelected ? "bg-primary/10" : "hover:bg-muted"
      )}
      onClick={onToggle}
    >
      <div className={cn(
        "h-5 w-5 shrink-0 mt-0.5 rounded border flex items-center justify-center transition-colors",
        isSelected ? "bg-primary border-primary" : "border-muted-foreground/30"
      )}>
        {isSelected && <Check className="h-3 w-3 text-primary-foreground" />}
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-medium truncate">
          {getLocalizedField(restaurant, "name")}
        </p>
        {restaurant.address && (
          <p className="text-sm text-muted-foreground truncate flex items-center gap-1 mt-0.5">
            <MapPin className="h-3 w-3 shrink-0" />
            {restaurant.address}
          </p>
        )}
      </div>
    </div>
  );

  // Mobile: Full-screen Drawer
  if (isMobile) {
    return (
      <>
        {triggerButton}
        <Drawer open={open} onOpenChange={handleOpenChange}>
          <DrawerContent 
            className="flex flex-col"
            style={{ 
              height: drawerHeight,
              maxHeight: drawerHeight,
              transition: 'height 0.15s ease-out, max-height 0.15s ease-out'
            }}
          >
            <DrawerHeader className="pb-2 shrink-0">
              <DrawerTitle>
                {t("community.selectRestaurants", "选择餐厅")}
                {pendingValue.length > 0 && (
                  <Badge variant="secondary" className="ml-2">
                    {pendingValue.length}
                  </Badge>
                )}
              </DrawerTitle>
            </DrawerHeader>

            {/* Search Input */}
            <div className="px-4 pb-3 shrink-0">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder={t("community.searchRestaurant", "搜索餐厅...")}
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="pl-9"
                />
              </div>
            </div>

            {/* Selected Preview */}
            {pendingValue.length > 0 && (
              <div className="px-4 pb-3 shrink-0">
                <div className="flex flex-wrap gap-1.5">
                  {pendingValue.map((id) => {
                    const restaurant = restaurants?.find((r) => r.id === id);
                    if (!restaurant) return null;
                    return (
                      <Badge
                        key={id}
                        variant="secondary"
                        className="gap-1 pr-1"
                      >
                        <span className="truncate max-w-[120px]">
                          {getLocalizedField(restaurant, "name")}
                        </span>
                        <button
                          type="button"
                          className="hover:bg-muted-foreground/20 rounded-full p-0.5"
                          onClick={(e) => {
                            e.stopPropagation();
                            setPendingValue((prev) => prev.filter((i) => i !== id));
                          }}
                        >
                          <X className="h-3 w-3" />
                        </button>
                      </Badge>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Restaurant List */}
            <div className="flex-1 overflow-y-auto px-4 min-h-0">
              <div className="space-y-1 pb-4">
                {filteredRestaurants.map((restaurant) => (
                  <RestaurantItem
                    key={restaurant.id}
                    restaurant={restaurant}
                    isSelected={pendingValue.includes(restaurant.id)}
                    onToggle={() => toggleRestaurant(restaurant.id)}
                  />
                ))}

                {filteredRestaurants.length === 0 && search && (
                  <div className="py-6 text-center text-muted-foreground">
                    {t("community.noRestaurantFound", "未找到匹配的餐厅")}
                  </div>
                )}
              </div>
            </div>

            {/* Footer Buttons */}
            <DrawerFooter className="pt-2">
              <div className="flex gap-3">
                <Button
                  variant="outline"
                  className="flex-1"
                  onClick={() => handleOpenChange(false)}
                >
                  {t("common.cancel", "取消")}
                </Button>
                <Button className="flex-1" onClick={handleConfirm}>
                  {t("community.confirmSelection", "确认选择")}
                  {pendingValue.length > 0 && ` (${pendingValue.length})`}
                </Button>
              </div>
            </DrawerFooter>
          </DrawerContent>
        </Drawer>
      </>
    );
  }

  // Desktop: Popover
  return (
    <Popover open={open} onOpenChange={handleOpenChange}>
      <PopoverTrigger asChild>{triggerButton}</PopoverTrigger>
      <PopoverContent className="w-80 p-0" align="start">
        <div className="p-3 border-b">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder={t("community.searchRestaurant", "搜索餐厅...")}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
        </div>
        
        {/* Selected Preview */}
        {value.length > 0 && (
          <div className="p-3 border-b">
            <div className="flex flex-wrap gap-1.5">
              {value.map((id) => {
                const restaurant = restaurants?.find((r) => r.id === id);
                if (!restaurant) return null;
                return (
                  <Badge
                    key={id}
                    variant="secondary"
                    className="gap-1 pr-1"
                  >
                    <span className="truncate max-w-[100px]">
                      {getLocalizedField(restaurant, "name")}
                    </span>
                    <button
                      type="button"
                      className="hover:bg-muted-foreground/20 rounded-full p-0.5"
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDesktopToggle(id);
                      }}
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </Badge>
                );
              })}
            </div>
          </div>
        )}

        <div className="max-h-64 overflow-y-auto p-2">
          {filteredRestaurants.map((restaurant) => (
            <RestaurantItem
              key={restaurant.id}
              restaurant={restaurant}
              isSelected={value.includes(restaurant.id)}
              onToggle={() => handleDesktopToggle(restaurant.id)}
            />
          ))}
          
          {filteredRestaurants.length === 0 && search && (
            <div className="py-4 text-center text-muted-foreground text-sm">
              {t("community.noRestaurantFound", "未找到匹配的餐厅")}
            </div>
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
};

export default MultiRestaurantSelectDrawer;
